              <tr><td style="font-size:12px; line-height:18px; color:#cbd5e1; text-align:right;"><strong style="color:#ffffff;">Generado:</strong><br>{{generated_at}}</td></tr>
              <tr><td style="font-size:12px; line-height:18px; color:#cbd5e1; text-align:right; padding-top:8px;"><strong style="color:#ffffff;">Fuente:</strong><br>Producción / iTop CMDB</td></tr>
